const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_ANON_KEY!);

export async function joinTeamChannel(teamId: string) {
  const topic = `team-${teamId}`;

  const channel = supabase.channel(topic, {
    config: {
      private: true,
      broadcast: { self: true }, // Sender sees their own broadcast events
      presence: { key: supabase.auth.user()?.id },
    },
  });

  // --- SURFACE 1: Broadcast (Ephemeral events like 'typing') ---
  channel.on('broadcast', { event: 'typing' }, ({ payload }) => {
    console.log(`${payload.user_name} is typing...`);
  });

  // --- SURFACE 2: Presence (Ephemeral state like 'online users') ---
  channel.on('presence', { event: 'sync' }, () => {
    const state = channel.presenceState();
    console.log('Online users:', Object.values(state).flat());
  });

  // --- SURFACE 3: Postgres Changes (Durable message log) ---
  channel.on(
    'postgres_changes',
    { event: 'INSERT', schema: 'public', table: 'team_messages', filter: `team_id=eq.${teamId}` },
    (payload) => {
      console.log('New message received:', payload.new.body);
    }
  );

  // Subscribe and wait for connection
  await new Promise<void>((resolve, reject) => {
    channel.subscribe((status, err) => {
      if (status === 'SUBSCRIBED') resolve();
      else if (err) reject(err);
    });
  });

  // IMPORTANT: Wait for Postgres Changes to settle (Gap #59)
  // Private channels require a short delay after subscription before 
  // postgres_changes events are reliably delivered.
  await new Promise(r => setTimeout(r, 1500));

  // Track presence
  await channel.track({ user_name: 'Alice', status: 'online' });

  return {
    channel,
    // Helper to send a typing event
    sendTyping: (userName: string) => 
      channel.send({ type: 'broadcast', event: 'typing', payload: { user_name: userName } }),
    // Helper to send a durable message
    sendMessage: async (text: string) => {
      const { error } = await supabase
        .from('team_messages')
        .insert({ team_id: teamId, body: text });
      if (error) throw error;
    }
  };
}
```

